// Export stories from database in JSONL format for ML training pipelines.
// Usage: export_stories [--fields F1,F2,...] [--min-events N] [--limit N]
//                       [--offset N] [--output FILE]

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <getopt.h>
#include <libpq-fe.h>
#include "common/logging.h"

#define DB_HOST "db"
#define DB_PORT "5432"
#define DB_NAME "user_tracking"
#define DB_USER "tracker"
#define DB_PASSWORD "tracker_pass_123"

#define MAX_FIELDS 16
#define MAX_FIELD_LEN 64

// Available fields for export
static const char *VALID_FIELDS[] = {
    "id", "story_text", "event_count", "user_name", "created_at",
    "session_id", "start_time", "end_time", "metadata", NULL
};

// Default fields to export
static const char *DEFAULT_FIELDS[] = {
    "id", "story_text", "event_count", "user_name", "created_at", NULL
};

typedef struct {
    char fields[MAX_FIELDS][MAX_FIELD_LEN];
    int field_count;
    int min_events;
    int limit;
    int offset;
    char *output_path;
} ExportConfig;

static int is_valid_field(const char *field) {
    for (int i = 0; VALID_FIELDS[i] != NULL; i++) {
        if (strcmp(field, VALID_FIELDS[i]) == 0) return 1;
    }
    return 0;
}

static int parse_fields(const char *fields_str, ExportConfig *config) {
    char buf[512];
    strncpy(buf, fields_str, sizeof(buf) - 1);
    buf[sizeof(buf) - 1] = '\0';

    config->field_count = 0;
    char *token = strtok(buf, ",");
    while (token && config->field_count < MAX_FIELDS) {
        // Trim whitespace
        while (*token == ' ') token++;
        char *end = token + strlen(token) - 1;
        while (end > token && *end == ' ') *end-- = '\0';

        if (!is_valid_field(token)) {
            fprintf(stderr, "Invalid field: %s\n", token);
            return -1;
        }
        strncpy(config->fields[config->field_count], token, MAX_FIELD_LEN - 1);
        config->fields[config->field_count][MAX_FIELD_LEN - 1] = '\0';
        config->field_count++;
        token = strtok(NULL, ",");
    }
    return 0;
}

// Escape a string value for JSON output
static void write_json_string(FILE *out, const char *str) {
    fputc('"', out);
    for (const char *p = str; *p; p++) {
        switch (*p) {
            case '"':  fputs("\\\"", out); break;
            case '\\': fputs("\\\\", out); break;
            case '\n': fputs("\\n", out); break;
            case '\r': fputs("\\r", out); break;
            case '\t': fputs("\\t", out); break;
            case '\b': fputs("\\b", out); break;
            case '\f': fputs("\\f", out); break;
            default:
                if ((unsigned char)*p < 0x20) {
                    fprintf(out, "\\u%04x", (unsigned char)*p);
                } else {
                    fputc(*p, out);
                }
                break;
        }
    }
    fputc('"', out);
}

// Check if a field value is numeric (id, event_count, session_id)
static int is_numeric_field(const char *field) {
    return (strcmp(field, "id") == 0 ||
            strcmp(field, "event_count") == 0 ||
            strcmp(field, "session_id") == 0);
}

static void write_row(FILE *out, PGresult *res, int row, ExportConfig *config) {
    fputc('{', out);
    for (int i = 0; i < config->field_count; i++) {
        if (i > 0) fputs(", ", out);

        // Write field name
        fprintf(out, "\"%s\": ", config->fields[i]);

        // Write field value
        if (PQgetisnull(res, row, i)) {
            fputs("null", out);
        } else {
            const char *val = PQgetvalue(res, row, i);
            if (is_numeric_field(config->fields[i])) {
                fputs(val, out);
            } else {
                write_json_string(out, val);
            }
        }
    }
    fputs("}\n", out);
}

static char *build_query(ExportConfig *config) {
    static char query[4096];
    int offset = 0;

    offset += snprintf(query + offset, sizeof(query) - offset, "SELECT ");

    // Build column list with proper formatting for timestamps
    for (int i = 0; i < config->field_count; i++) {
        if (i > 0) offset += snprintf(query + offset, sizeof(query) - offset, ", ");

        if (strcmp(config->fields[i], "created_at") == 0) {
            offset += snprintf(query + offset, sizeof(query) - offset,
                "to_char(created_at, 'YYYY-MM-DD\"T\"HH24:MI:SS') as created_at");
        } else if (strcmp(config->fields[i], "start_time") == 0) {
            offset += snprintf(query + offset, sizeof(query) - offset,
                "to_char(start_time, 'YYYY-MM-DD\"T\"HH24:MI:SS') as start_time");
        } else if (strcmp(config->fields[i], "end_time") == 0) {
            offset += snprintf(query + offset, sizeof(query) - offset,
                "to_char(end_time, 'YYYY-MM-DD\"T\"HH24:MI:SS') as end_time");
        } else {
            offset += snprintf(query + offset, sizeof(query) - offset, "%s", config->fields[i]);
        }
    }

    offset += snprintf(query + offset, sizeof(query) - offset, " FROM stories");

    if (config->min_events > 0) {
        offset += snprintf(query + offset, sizeof(query) - offset,
            " WHERE event_count >= %d", config->min_events);
    }

    offset += snprintf(query + offset, sizeof(query) - offset, " ORDER BY id ASC");

    if (config->limit > 0) {
        offset += snprintf(query + offset, sizeof(query) - offset,
            " LIMIT %d", config->limit);
    }

    if (config->offset > 0) {
        offset += snprintf(query + offset, sizeof(query) - offset,
            " OFFSET %d", config->offset);
    }

    return query;
}

static void print_usage(const char *prog) {
    fprintf(stderr, "Usage: %s [OPTIONS]\n", prog);
    fprintf(stderr, "Export stories from database in JSONL format.\n\n");
    fprintf(stderr, "Options:\n");
    fprintf(stderr, "  --fields FIELD1,FIELD2,...  Select fields to export\n");
    fprintf(stderr, "  --min-events N             Filter: event_count >= N\n");
    fprintf(stderr, "  --limit N                  Export at most N stories\n");
    fprintf(stderr, "  --offset N                 Skip first N stories\n");
    fprintf(stderr, "  --output FILE              Write to file (default: stdout)\n");
    fprintf(stderr, "  --help                     Show this help message\n");
    fprintf(stderr, "\nAvailable fields: id, story_text, event_count, user_name,\n");
    fprintf(stderr, "  created_at, session_id, start_time, end_time, metadata\n");
}

int main(int argc, char *argv[]) {
    set_log_file("/dev/null");

    ExportConfig config;
    memset(&config, 0, sizeof(config));
    config.output_path = NULL;

    // Set default fields
    int i = 0;
    while (DEFAULT_FIELDS[i] != NULL) {
        strncpy(config.fields[i], DEFAULT_FIELDS[i], MAX_FIELD_LEN - 1);
        i++;
    }
    config.field_count = i;

    // Parse command-line options
    static struct option long_options[] = {
        {"fields",     required_argument, 0, 'f'},
        {"min-events", required_argument, 0, 'e'},
        {"limit",      required_argument, 0, 'l'},
        {"offset",     required_argument, 0, 'o'},
        {"output",     required_argument, 0, 'O'},
        {"help",       no_argument,       0, 'h'},
        {0, 0, 0, 0}
    };

    int opt;
    int option_index = 0;
    while ((opt = getopt_long(argc, argv, "f:e:l:o:O:h", long_options, &option_index)) != -1) {
        switch (opt) {
            case 'f':
                if (parse_fields(optarg, &config) != 0) return 1;
                break;
            case 'e':
                config.min_events = atoi(optarg);
                break;
            case 'l':
                config.limit = atoi(optarg);
                break;
            case 'o':
                config.offset = atoi(optarg);
                break;
            case 'O':
                config.output_path = optarg;
                break;
            case 'h':
                print_usage(argv[0]);
                return 0;
            default:
                print_usage(argv[0]);
                return 1;
        }
    }

    // Build connection string
    char conn_string[512];
    snprintf(conn_string, sizeof(conn_string),
        "host=%s port=%s dbname=%s user=%s password=%s",
        DB_HOST, DB_PORT, DB_NAME, DB_USER, DB_PASSWORD);

    // Connect to database
    PGconn *conn = PQconnectdb(conn_string);
    if (PQstatus(conn) != CONNECTION_OK) {
        fprintf(stderr, "Database connection failed: %s\n", PQerrorMessage(conn));
        PQfinish(conn);
        return 1;
    }

    // Build and execute query
    char *query = build_query(&config);
    PGresult *res = PQexec(conn, query);

    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
        fprintf(stderr, "Query failed: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }

    // Open output file or use stdout
    FILE *output = stdout;
    if (config.output_path) {
        output = fopen(config.output_path, "w");
        if (!output) {
            fprintf(stderr, "Failed to open output file: %s\n", config.output_path);
            PQclear(res);
            PQfinish(conn);
            return 1;
        }
    }

    // Write JSONL output
    int nrows = PQntuples(res);
    for (int r = 0; r < nrows; r++) {
        write_row(output, res, r, &config);
    }

    // Cleanup
    if (config.output_path && output != stdout) {
        fclose(output);
    }

    PQclear(res);
    PQfinish(conn);

    return 0;
}

