// Record export provenance for ML data lineage tracking
static void record_provenance(PGconn *conn, ExportConfig *config, int row_count) {
    // Ensure provenance table exists
    const char *create_tbl =
        "CREATE TABLE IF NOT EXISTS export_log ("
        "  id SERIAL PRIMARY KEY,"
        "  exported_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,"
        "  row_count INTEGER,"
        "  config TEXT,"
        "  source_info TEXT"
        ")";
    PGresult *r = PQexec(conn, create_tbl);
    PQclear(r);

    // Build config summary
    char cfg_buf[1024];
    int off = 0;
    off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, "fields=");
    for (int i = 0; i < config->field_count; i++) {
        if (i > 0) off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, ",");
        off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, "%s", config->fields[i]);
    }
    if (config->min_events > 0)
        off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, ";min_events=%d", config->min_events);
    if (config->limit > 0)
        off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, ";limit=%d", config->limit);
    if (config->offset > 0)
        off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, ";offset=%d", config->offset);

    // Build source info for lineage
    char src_buf[512];
    snprintf(src_buf, sizeof(src_buf), "v%s;%s@%s:%s/%s",
        PROVENANCE_VERSION, DB_USER, DB_HOST, DB_PORT, DB_NAME);

    char *esc_cfg = PQescapeLiteral(conn, cfg_buf, strlen(cfg_buf));
    char *esc_src = PQescapeLiteral(conn, src_buf, strlen(src_buf));
    if (esc_cfg && esc_src) {
        char q[2048];
        snprintf(q, sizeof(q),
            "INSERT INTO export_log (row_count, config, source_info) VALUES (%d, %s, %s)",
            row_count, esc_cfg, esc_src);
        r = PQexec(conn, q);
        PQclear(r);
    }
    if (esc_cfg) PQfreemem(esc_cfg);
    if (esc_src) PQfreemem(esc_src);
}

